    const handleUpdateUser = async (e) => {
        e.preventDefault();
        
        try {
            const token = localStorage.getItem('token');
            const updateData = {
                firstName: newUserData.firstName,
                lastName: newUserData.lastName,
                email: newUserData.email,
                role: newUserData.role
            };
    
            // Only include password if it's provided
            if (newUserData.password.trim()) {
                updateData.password = newUserData.password;
            }
    
            const response = await fetch(`http://localhost:5000/api/admin/users/${editingUser._id}`, {
                method: 'PUT',
                headers: {
                    'Content-Type': 'application/json',
                    'Authorization': `Bearer ${token}`
                },
                body: JSON.stringify(updateData)
            });
    
            if (response.ok) {
                const updatedUser = await response.json();
                
                // Update the user in your allUsers state
                setAllUsers(prevUsers => 
                    prevUsers.map(user => 
                        user._id === editingUser._id ? updatedUser : user
                    )
                );
    
                // Close the modal and reset form
                setShowEditUserForm(false);
                setEditingUser(null);
                setNewUserData({
                    firstName: '',
                    lastName: '',
                    email: '',
                    password: '',
                    role: 'student'
                });
    
            } else {
                const errorData = await response.json();
                throw new Error(errorData.message || 'Failed to update user');
            }
        } catch (error) {
            console.error('Error updating user:', error);
            throw error; // Re-throw so SweetAlert can catch it
        }
    };

