                        await fetchPendingUsers(token);
                        await fetchAllUsers(token);
                        console.log('✅ Users fetch completed');
                    } catch (error) {
                        console.error('❌ Users fetch failed:', error);
                    }
                }

            } catch (error) {
                console.error('❌ Authentication error:', error);
