                                        ? 'border-gray-600 text-gray-300 bg-gray-700 hover:bg-gray-600' 
                                        : 'border-gray-300 text-gray-700 bg-white hover:bg-gray-50'
                                }`}
                            >
                                Close
                            </button>
                        </div>
                    </div>
